    const homeGrid = document.getElementById("homeGrid");
    const mainNav = document.getElementById("mainNav");
    const drawerNav = document.getElementById("drawerNav");
    const drawerSubNav = document.getElementById("drawerSubNav");
    const drawer = document.getElementById("drawer");
    const articleShell = document.getElementById("articleShell");
    const emptyState = document.getElementById("emptyState");

    function makeButton(item, className) {
      const button = document.createElement("button");
      button.type = "button";
      button.className = className;
      button.dataset.nav = item[0];
      button.textContent = item[1];
      return button;
    }

    function renderNav() {
      navItems.forEach((item) => {
        mainNav.appendChild(makeButton(item, "nav-link"));
        const drawerButton = makeButton(item, "");
        drawerNav.appendChild(drawerButton);
      });

      const subTitle = document.createElement("div");
      subTitle.className = "drawer-section-title";
      subTitle.textContent = "More categories";
      drawerSubNav.appendChild(subTitle);

      subItems.forEach((item) => {
        drawerSubNav.appendChild(makeButton(item, ""));
      });
    }

    function articleLink(article, className = "") {
      return `<a class="${className} story-link" href="#article/${article.slug}" data-slug="${article.slug}">${article.title}</a>`;
    }

    function articleImage(article) {
      return `<img src="${article.image}" alt="${article.title}" loading="lazy" onerror="this.onerror=null;this.src='https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1200&q=85';">`;
    }

    function getCategoryStories(filter) {
      return articles.filter((article) => article.section === filter || article.sub === filter);
    }

    function getEditorPicks(currentArticle) {
      const sameSection = articles.filter((item) => item.slug !== currentArticle.slug && item.section === currentArticle.section);
      const fallback = articles.filter((item) => item.slug !== currentArticle.slug && item.section !== currentArticle.section);
      return [...sameSection, ...fallback].slice(0, 5);
    }

    function renderCategoryPage(filter) {
      const section = sections.find((item) => item.id === filter);
      const title = section ? section.label : filter;
      const stories = getCategoryStories(filter);
      const visibleStories = stories;

      if (!visibleStories.length) return 0;

      const block = document.createElement("section");
      block.className = "category-section";
      block.innerHTML = `
        <div class="section-band">${title}</div>
        <div class="category-card-grid">
          ${visibleStories.map((article) => `
            <article class="category-card">
              <a class="story-link" href="#article/${article.slug}" data-slug="${article.slug}">
                ${articleImage(article)}
              </a>
              <h2 class="headline">${articleLink(article)}</h2>
              <span class="date-small">${article.date}</span>
            </article>
          `).join("")}
        </div>
      `;
      homeGrid.appendChild(block);

      return 1;
    }

    function renderHome(filter = "all") {
      document.body.classList.remove("article-mode");
      homeGrid.innerHTML = "";
      homeGrid.classList.toggle("category-view", filter !== "all");
      let visibleSections = 0;

      if (filter !== "all" && sections.some((section) => section.id === filter)) {
        visibleSections = renderCategoryPage(filter);
        emptyState.classList.toggle("show", visibleSections === 0);
        setActive(filter);
        window.scrollTo({ top: 0, behavior: "smooth" });
        return;
      }

      sections.filter((section) => filter !== "all" || section.home !== false).forEach((section) => {
        const stories = articles.filter((article) => {
          if (filter === "all") return article.section === section.id;
          return article.section === section.id && (article.section === filter || article.sub === filter);
        });

        if (!stories.length) return;
        visibleSections += 1;
        const lead = stories[0];
        const rest = stories.slice(1, 5);

        const block = document.createElement("section");
        block.className = "section-block";
        block.id = section.id;
        block.innerHTML = `
          <div class="section-band ${section.color}">${section.label}</div>
          <article class="lead-card">
            <a class="story-link" href="#article/${lead.slug}" data-slug="${lead.slug}">
              ${articleImage(lead)}
            </a>
            <span class="kicker">${lead.kicker}</span>
            <h2 class="headline">${articleLink(lead)}</h2>
            <span class="date-small">${lead.date}</span>
          </article>
          <div class="story-list">
            ${rest.map((article) => `
              <article>
                <span class="kicker">${article.kicker}</span>
                <h3 class="headline">${articleLink(article)}</h3>
              </article>
            `).join("")}
          </div>
          <button class="more-btn" type="button" data-more-category="${section.id}">More stories</button>
        `;
        homeGrid.appendChild(block);
      });

      emptyState.classList.toggle("show", visibleSections === 0);
      setActive(filter);
      window.scrollTo({ top: 0, behavior: "smooth" });
    }

    function getSearchMatches(query) {
      const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
      return articles.filter((article) => {
        const text = `${article.title} ${article.kicker} ${article.section} ${article.sub} ${article.author}`.toLowerCase();
        return terms.every((term) => text.includes(term));
      });
    }

    function renderSearchResults(query) {
      const matches = getSearchMatches(query);
      document.body.classList.remove("article-mode");
      homeGrid.innerHTML = "";
      homeGrid.classList.add("category-view");
      setActive("");

      const block = document.createElement("section");
      block.className = "category-section";
      block.innerHTML = `
        <div class="section-band">Search: ${query}</div>
        ${matches.length ? `
          <div class="category-card-grid">
            ${matches.map((article) => `
              <article class="category-card">
                <a class="story-link" href="#article/${article.slug}" data-slug="${article.slug}">
                  ${articleImage(article)}
                </a>
                <span class="kicker">${article.kicker}</span>
                <h2 class="headline">${articleLink(article)}</h2>
                <span class="date-small">${article.date}</span>
              </article>
            `).join("")}
          </div>
        ` : `<div class="empty-state show">No articles found for "${query}". Try another keyword.</div>`}
      `;

      homeGrid.appendChild(block);
      emptyState.classList.remove("show");
      window.scrollTo({ top: 0, behavior: "smooth" });
    }

    function renderArticle(slug) {
      const article = articles.find((item) => item.slug === slug) || articles[0];
      const recommendations = articles.filter((item) => item.slug !== article.slug).slice(0, 4);
      const editorPicks = getEditorPicks(article);
      document.body.classList.add("article-mode");
      setActive(article.section);

      articleShell.innerHTML = `
        <div class="article-layout">
          <article>
            <div class="article-category">${article.kicker}</div>
            <h1 class="article-title">${article.title}</h1>
            <p class="byline">By: <strong>${article.author}</strong> - PRESSPOINT / ${article.date}</p>
            <div class="share-row">
              <span>Share:</span>
              <span class="share-dot">f</span>
              <span class="share-dot">x</span>
              <span class="share-dot">@</span>
            </div>
            <div class="ad-wide">Article banner advertisement</div>
            <figure class="article-main-image">
              ${articleImage(article)}
              <figcaption class="caption">${article.caption}</figcaption>
            </figure>
            <div class="article-body">
              ${article.body.map((paragraph) => `<p>${paragraph}</p>`).join("")}
            </div>
            <a class="source-link" href="${article.sourceUrl}" target="_blank" rel="noopener">Read original source</a>
            <div class="read-label">Read: Related updates and explainer stories</div>
            <div class="newsletter-box" id="newsletter">
              <h3>Subscribe to our daily newsletter</h3>
              <input type="email" placeholder="Email Address" aria-label="Email address">
              <button class="newsletter-signup" type="button">Sign me up</button>
              <p class="newsletter-message" aria-live="polite"></p>
            </div>
            <div class="recommend-row">
              ${recommendations.map((item) => `
                <a class="recommend-card story-link" href="#article/${item.slug}" data-slug="${item.slug}">
                  ${articleImage(item)}
                  <h3>${item.title}</h3>
                </a>
              `).join("")}
            </div>
            <a class="back-home nav-home" href="#home">Back to homepage</a>
          </article>

          <aside class="article-side">
            <div class="side-card">
              <h3>Editor's Pick</h3>
              <div class="editor-list">
                ${editorPicks.map((item) => `
                  <a class="editor-item story-link" href="#article/${item.slug}" data-slug="${item.slug}" title="${item.title}">
                    ${articleImage(item)}
                    <span>${item.title}</span>
                  </a>
                `).join("")}
              </div>
            </div>
            <div class="mini-ad">Follow us on Facebook</div>
            <div class="mini-ad">Subscribe to our newsletter</div>
          </aside>
        </div>
      `;

      window.scrollTo({ top: 0, behavior: "smooth" });
    }

    function renderCompanyPage(pageKey) {
      const page = companyPages[pageKey] || companyPages.about;
      document.body.classList.add("article-mode");
      setActive("");
      drawer.classList.remove("open");

      articleShell.innerHTML = `
        <div class="company-page">
          <article>
            <h1>${page.title}</h1>
            ${page.html}
            <a class="back-home nav-home" href="#home">Back to homepage</a>
          </article>
        </div>
      `;

      window.scrollTo({ top: 0, behavior: "smooth" });
    }

    function renderServicePage(pageKey) {
      const page = servicePages[pageKey] || servicePages.contact;
      document.body.classList.add("article-mode");
      setActive("");
      drawer.classList.remove("open");

      articleShell.innerHTML = `
        <div class="company-page service-page">
          <article>
            <h1>${page.title}</h1>
            ${page.html}
            <hr>
            <h2>Additional Services</h2>
            ${servicePages.additional.html}
            <a class="back-home nav-home" href="#home">Back to homepage</a>
          </article>
        </div>
      `;

      window.scrollTo({ top: 0, behavior: "smooth" });
    }

    function setActive(filter) {
      document.querySelectorAll("[data-nav]").forEach((button) => {
        button.classList.toggle("active", button.dataset.nav === filter);
      });
    }

    function handleNav(filter) {
      drawer.classList.remove("open");
      const routeMap = {
        cdn: "cebudailynews",
        preen: "preen",
        cebudailynews: "cebudailynews",
        scout: "scout",
        nolisoli: "nolisoli",
        multisports: "multisports",
        fnbreport: "fnbreport",
        dziq990am: "dziq990am",
        mobility: "mobility",
        newsletter: "all"
      };
      const target = routeMap[filter] || filter;
      if (filter === "latest" || filter === "headlines" || filter === "news") {
        history.pushState(null, "", "#home");
        renderHome("all");
        return;
      }
      history.pushState(null, "", `#${target}`);
      renderHome(target);
    }

    function handleHash() {
      const hash = window.location.hash.replace("#", "");
      if (hash.startsWith("article/")) {
        renderArticle(hash.split("/")[1]);
        return;
      }
      if (hash.startsWith("company/")) {
        const slug = hash.split("/")[1];
        const page = Object.entries(companyPages).find((entry) => entry[1].slug === slug);
        renderCompanyPage(page ? page[0] : "about");
        return;
      }
      if (hash.startsWith("services/")) {
        const slug = hash.split("/")[1];
        const page = Object.entries(servicePages).find((entry) => entry[1].slug === slug);
        renderServicePage(page ? page[0] : "contact");
        return;
      }
      if (hash.startsWith("search/")) {
        renderSearchResults(decodeURIComponent(hash.slice(7)));
        return;
      }
      if (hash.endsWith("/more")) {
        const filter = hash.split("/")[0];
        if (sections.some((section) => section.id === filter)) {
          history.replaceState(null, "", `#${filter}`);
          renderHome(filter);
          return;
        }
      }
      if (sections.some((section) => section.id === hash)) {
        renderHome(hash);
        return;
      }
      renderHome("all");
    }

    document.addEventListener("click", (event) => {
      const story = event.target.closest(".story-link");
      if (story) {
        event.preventDefault();
        history.pushState(null, "", story.getAttribute("href"));
        renderArticle(story.dataset.slug);
        return;
      }

      const companyLink = event.target.closest(".company-link");
      if (companyLink) {
        event.preventDefault();
        history.pushState(null, "", companyLink.getAttribute("href"));
        renderCompanyPage(companyLink.dataset.page);
        return;
      }

      const serviceLink = event.target.closest(".service-link");
      if (serviceLink) {
        event.preventDefault();
        history.pushState(null, "", serviceLink.getAttribute("href"));
        renderServicePage(serviceLink.dataset.service);
        return;
      }

      const moreCategory = event.target.closest("[data-more-category]");
      if (moreCategory) {
        event.preventDefault();
        const filter = moreCategory.dataset.moreCategory;
        history.pushState(null, "", `#${filter}`);
        renderHome(filter);
        return;
      }

      const signupButton = event.target.closest(".newsletter-signup");
      if (signupButton) {
        event.preventDefault();
        const box = signupButton.closest(".newsletter-box");
        const input = box.querySelector("input[type='email']");
        const message = box.querySelector(".newsletter-message");
        const email = input.value.trim();
        const isValidEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

        box.classList.remove("is-success", "is-error");
        if (!isValidEmail) {
          box.classList.add("is-error");
          message.textContent = "Please enter a valid email address.";
          input.focus();
          return;
        }

        box.classList.add("is-success");
        message.textContent = "You are signed up for PRESSPOINT alerts.";
        signupButton.textContent = "Signed up";
        signupButton.disabled = true;
        input.disabled = true;
        return;
      }

      const nav = event.target.closest("[data-nav]");
      if (nav) {
        event.preventDefault();
        handleNav(nav.dataset.nav);
        return;
      }

      if (event.target.closest(".nav-home")) {
        event.preventDefault();
        history.pushState(null, "", "#home");
        renderHome("all");
      }
    });

    document.getElementById("menuBtn").addEventListener("click", () => {
      drawer.classList.add("open");
    });

    document.getElementById("closeDrawer").addEventListener("click", () => {
      drawer.classList.remove("open");
    });

    document.getElementById("searchForm").addEventListener("submit", (event) => {
      event.preventDefault();
      const input = document.getElementById("searchInput");
      const query = input.value.trim();
      if (!query) {
        input.focus();
        return;
      }

      history.pushState(null, "", `#search/${encodeURIComponent(query)}`);
      renderSearchResults(query);
      input.value = "";
    });

    window.addEventListener("popstate", handleHash);

    renderNav();
    handleHash();
